lemma LastCharDeterminesClassification(s: string)
  requires ValidSentence(s)
  requires |s| >= 1
  ensures s[|s| - 1] == 'o' ==> EndsWith(s, "po")
  ensures s[|s| - 1] == 'u' ==> (EndsWith(s, "desu") || EndsWith(s, "masu"))
