  }
  if EndsWith(s, "desu") {
    assert s[|s| - 4..] == "desu";
    assert s[|s| - 1] == 'u';
  }
  if EndsWith(s, "masu") {
    assert s[|s| - 4..] == "masu";
    assert s[|s| - 1] == 'u';
  }
  if EndsWith(s, "mnida") {
    assert s[|s| - 5..] == "mnida";
    assert s[|s| - 1] == 'a';
  }
}

method SuffixThree(sentences: seq<string>) returns (results: seq<string>)
  requires forall i :: 0 <= i < |sentences| ==> ValidSentence(sentences[i])
  ensures results == ClassifyAll(sentences)
